// $input.first().json IS the already-parsed Ollama JSON response
const resp = $input.first().json;
const specText = resp.message?.content || resp.response || 'Error: no Ollama response';

// Pull channelId from Build Prompt (HTTP Request replaced the json item)
const buildData = $('Build Prompt').first().json;
const channelId = buildData.channelId || '';
const description = buildData.description || '';

// Split into chunks for Slack (max 3000 chars per block)
const MAX_BLOCK = 2800;
const chunks = [];
let remaining = specText;
while (remaining.length > 0) {
  chunks.push(remaining.slice(0, MAX_BLOCK));
  remaining = remaining.slice(MAX_BLOCK);
}

const blocks = [
  { type: 'header', text: { type: 'plain_text', text: ':page_with_curl: Patent Specification Draft', emoji: true } },
  { type: 'section', text: { type: 'mrkdwn', text: '*Invention:* ' + description } },
  { type: 'divider' },
  { type: 'section', text: { type: 'mrkdwn', text: chunks[0] || 'No content generated.' } },
];

if (chunks.length > 1) {
  blocks.push({
    type: 'context',
    elements: [{ type: 'mrkdwn', text: ':page_facing_up: Full spec is ' + specText.length + ' chars. Remaining content follows in thread.' }]
  });
}

blocks.push({
  type: 'context',
  elements: [{ type: 'mrkdwn', text: ':warning: _AI-generated draft. Have a licensed patent attorney review before filing._' }]
});

return [{ json: {
  channelId,
  description,
  slackPayload: JSON.stringify({ channel: channelId, blocks }),
  extraChunks: chunks.slice(1),
  fullText: specText,
} }];

// If there are extra chunks, post them as thread replies
const resp = JSON.parse($input.first().json.data || '{}');
const ts = resp.ts || '';
const channelId = $input.first().json.channelId || '';
const extraChunks = $input.first().json.extraChunks || [];
const fullText = $input.first().json.fullText || '';

const threadMessages = extraChunks.map(chunk => ({
  channel: channelId,
  thread_ts: ts,
  text: chunk,
}));

return [{ json: {
  channelId,
  thread_ts: ts,
  threadMessages,
  fullText,
  hasMore: threadMessages.length > 0,
} }];
